"""canary_controller.py — advances or aborts canary rollout based on live metrics."""
import time
import boto3
from datadog import initialize, api as dd

ALB_LISTENER_ARN = "arn:aws:elasticloadbalancing:us-east-1:123456789012:listener/..."
STABLE_TG_ARN = "arn:aws:elasticloadbalancing:us-east-1:123456789012:targetgroup/stable/..."
CANARY_TG_ARN = "arn:aws:elasticloadbalancing:us-east-1:123456789012:targetgroup/canary/..."

# Ring schedule: (canary_pct, soak_minutes)
ROLLOUT_RINGS = [(1, 10), (5, 15), (10, 20), (25, 20), (50, 30), (100, 0)]

ERROR_RATE_LIMIT = 0.02   # abort if canary error rate > 2%
LATENCY_P99_LIMIT = 8.0  # abort if p99 latency > 8 s

elbv2 = boto3.client("elbv2", region_name="us-east-1")
initialize(api_key="${DATADOG_API_KEY}")  # substitute at deploy time


def set_canary_weight(canary_pct: int):
    stable_pct = 100 - canary_pct
    elbv2.modify_listener(
        ListenerArn=ALB_LISTENER_ARN,
        DefaultActions=[{
            "Type": "forward",
            "ForwardConfig": {
                "TargetGroups": [
                    {"TargetGroupArn": STABLE_TG_ARN, "Weight": stable_pct},
                    {"TargetGroupArn": CANARY_TG_ARN, "Weight": canary_pct},
                ]
            }
        }]
    )
    print(f"Traffic split set: canary={canary_pct}% stable={stable_pct}%")


def check_canary_health() -> bool:
    """Query Datadog for canary metrics; return True if healthy."""
    error_rate = dd.Metric.query(
        start=int(time.time()) - 300,
        end=int(time.time()),
        query='avg:agent.error_rate{version:canary}'
    )["series"][0]["pointlist"][-1][1]

    p99_latency = dd.Metric.query(
        start=int(time.time()) - 300,
        end=int(time.time()),
        query='p99:agent.session_duration_seconds{version:canary}'
    )["series"][0]["pointlist"][-1][1]

    if error_rate > ERROR_RATE_LIMIT:
        print(f"ABORT: canary error rate {error_rate:.3f} > {ERROR_RATE_LIMIT}")
        return False
    if p99_latency > LATENCY_P99_LIMIT:
        print(f"ABORT: canary p99 latency {p99_latency:.1f}s > {LATENCY_P99_LIMIT}s")
        return False
    return True


def run_rollout():
    for canary_pct, soak_minutes in ROLLOUT_RINGS:
        set_canary_weight(canary_pct)
        print(f"Soaking at {canary_pct}% for {soak_minutes} min...")
        time.sleep(soak_minutes * 60)

        if canary_pct < 100 and not check_canary_health():
            print("Rolling back to 0% canary")
            set_canary_weight(0)
            raise SystemExit(1)

    print("Rollout complete — canary is now 100%")


if __name__ == "__main__":
    run_rollout()
